import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, MyTable } from '../../includes';
import { TableCell, FormControl, Button } from '@material-ui/core';

const request = [
    {
        _id : 1, 
        fromId : 1, 
        toId : 2, 
        from: {
            name : "Emeka Chukwu",
            number :  "+23480857894"
        },
    },
    {
        _id : 1, 
        fromId : 1, 
        toId : 2, 
        from: {
            name : "Emeka Chukwu",
            number :  "+23480857894"
        },
    },
    {
        _id : 1, 
        fromId : 1, 
        toId : 2, 
        from: {
            name : "Emeka Chukwu",
            number :  "+23480857894"
        },
    },
]

const style = theme => ({
    root: {
        marginTop : 50,
        padding : 20,
        maxHeight : "calc(100%)",
    },
    cell : {
        padding : 5
    },
    btn : {
        textTransform : "lowercase",
    }
})
class _Requests extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "TRACKING REQUESTS",
        })(dispatch);
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes} = this.props;
        switch(cellMap){
            case "name" : return <TableCell className={classes.cell}>
                {row.from && row.from.name}
            </TableCell>
            case "number" : return <TableCell className={classes.cell}>
                {row.from && row.from.number}
            </TableCell>
            case "action" : return <TableCell className={classes.cell}>
                <FormControl style={{display : "flex", flexDirection : "row-reverse"}}>
                    <Button className={classes.btn} color="secondary">Delete</Button>
                    <Button className={classes.btn} color="primary">Approve</Button>
                </FormControl>
            </TableCell>
        }
    }
    render() {
        const {classes} = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["Name", "Number", "Request Actions"]}
                    dataMap={["name", "number", "action"]}
                    CellMap={this.cellMapFormat.bind(this)}
                    data={request}/>
            </div>
        );
    }
}


_Requests.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const Requests = connect(mapStateToProps)(withStyles(style)(_Requests));
export {Requests as default}